   506|  }
   507|
   508|  const store = getPublicChatSupabaseStore();
   509|  if (store.isConfigured()) {
   510|    try {
   511|      const messages = (await store.listMessages({ sessionId, clientId, limit })).map(toPublicSupabaseMessage);
   512|      return jsonResponse({
   513|        ok: true,
   514|        sessionId,
   515|        messageCount: messages.length,
